static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    auto *x_shape = context->GetInputShape(0);
    auto *w_shape = context->GetInputShape(1);
    if (x_shape == nullptr || w_shape == nullptr) {
        return ge::GRAPH_FAILED;
    }

    const int64_t n64 = x_shape->GetOriginShape().GetDim(0);
    const int64_t c64 = x_shape->GetOriginShape().GetDim(1);
    const int64_t h64 = x_shape->GetOriginShape().GetDim(2);
    const int64_t w64 = x_shape->GetOriginShape().GetDim(3);

    const int64_t wc64 = w_shape->GetOriginShape().GetDim(0);  // should equal C
    const int64_t wci64 = w_shape->GetOriginShape().GetDim(1); // should equal 1
    const int64_t kh64 = w_shape->GetOriginShape().GetDim(2);  // expected 3
    const int64_t kw64 = w_shape->GetOriginShape().GetDim(3);  // expected 3

    if (n64 <= 0 || c64 <= 0 || h64 <= 0 || w64 <= 0 || wc64 != c64 || wci64 != 1) {
        return ge::GRAPH_FAILED;
    }

    const int64_t outH64 = h64 - kh64 + 1;
    const int64_t outW64 = w64 - kw64 + 1;
    if (outH64 <= 0 || outW64 <= 0) {
        return ge::GRAPH_FAILED;
    }

    ConvDepthwise2dAsymmetricInputSquareKernelCustomTilingData td;
    const uint32_t N = static_cast<uint32_t>(n64);
    const uint32_t C = static_cast<uint32_t>(c64);
    const uint32_t H = static_cast<uint32_t>(h64);
    const uint32_t W = static_cast<uint32_t>(w64);
    const uint32_t KH = static_cast<uint32_t>(kh64);
    const uint32_t KW = static_cast<uint32_t>(kw64);
    const uint32_t OH = static_cast<uint32_t>(outH64);
    const uint32_t OW = static_cast<uint32_t>(outW64);

    // Choose blockDim based on (N*C)
    uint32_t blockDim = std::min<uint32_t>(N * C, 24u);
    if (blockDim == 0u) blockDim = 1u;
    context->SetBlockDim(blockDim);

    td.set_nSize(N);
    td.set_cSize(C);
    td.set_hSize(H);
    td.set_wSize(W);
    td.set_kernelH(KH);
    td.set_kernelW(KW);
    td.set_outH(OH);
    td.set_outW(OW);
    td.set_blockDim(blockDim);

    td.SaveToBuffer(context->GetRawTilingData()->GetData(),
                    context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(td.GetDataSize());

    size_t *workspaceSizes = context->GetWorkspaceSizes(1);
    workspaceSizes[0] = 0;
    return ge::GRAPH_SUCCESS;
}

